import{_ as e,o as i,c as l,a2 as r}from"./chunks/framework.BZO4qERu.js";const m=JSON.parse('{"title":"Cesium 雨雪天气效果","description":"","frontmatter":{},"headers":[],"relativePath":"cesium/rain.md","filePath":"cesium/rain.md"}'),t={name:"cesium/rain.md"};function o(s,a,n,c,d,u){return i(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="cesium-雨雪天气效果" tabindex="-1">Cesium 雨雪天气效果 <a class="header-anchor" href="#cesium-雨雪天气效果" aria-label="Permalink to &quot;Cesium 雨雪天气效果&quot;">​</a></h1><p><a class="demo-link" href="/cesium/rain" target="_blank">打开主应用 Demo：/cesium/rain</a></p><h2 id="功能简介" tabindex="-1">功能简介 <a class="header-anchor" href="#功能简介" aria-label="Permalink to &quot;功能简介&quot;">​</a></h2><p>雨雪天气适合用来增强三维地图的现场感，比如应急指挥、交通态势、园区巡检、城市运行监控等场景。</p><p>当前示例主要由两部分组成：</p><ul><li>后处理 shader：给画面增加阴天、湿润、雪花或风线效果。</li><li>粒子系统：在雨天模式下生成更明显的前景雨线。</li></ul><h2 id="适用场景" tabindex="-1">适用场景 <a class="header-anchor" href="#适用场景" aria-label="Permalink to &quot;适用场景&quot;">​</a></h2><ul class="meta-list"><li>应急指挥：模拟恶劣天气下的城市运行环境。</li><li>交通管理：展示降雨、降雪对道路通行的影响。</li><li>可视化演示：让地图 Demo 更容易被业务用户理解。</li></ul><h2 id="实现思路" tabindex="-1">实现思路 <a class="header-anchor" href="#实现思路" aria-label="Permalink to &quot;实现思路&quot;">​</a></h2><ol><li>使用 <code>PostProcessStage</code> 对最终画面做统一调色。</li><li>雨天叠加 <code>ParticleSystem</code>，让近景雨线更明显。</li><li>不同天气使用不同配置：密度、速度、倾斜角、透明度。</li><li>雪花效果用 shader 生成多层不同尺度的随机雪片。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><ul><li>背景太亮时，雨线和雪花会不明显，需要降低天空亮度或切换到城市近景。</li><li>过高的密度会让画面变脏，应该优先调大粒径，再微调密度。</li><li>后处理应当支持关闭和恢复场景状态，避免切换页面后影响其他 Cesium 页面。</li></ul>',12)])])}const _=e(t,[["render",o]]);export{m as __pageData,_ as default};
